#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=100005;
int n,m,ru[N],chu[N],vis[N];
vector<int> g[N];
ll p[N],q[N];
ll gcd(ll x,ll y)
{
//	cout<<x<<" "<<y<<endl;
	if(x<y) swap(x,y);
	if(y==0) return x;
	return gcd(y,x%y);
}
void add(int x,ll y,ll z)
{
//	cout<<p[x]<<" "<<q[x]<<" "<<y<<" "<<z<<"\n";
//	cout<<" gcd ("<<q[x]<<" , "<<z<<")"<<endl;
	ll gc=gcd(q[x],z);
//	cout<<"ok"<<endl;
	ll tmp1=z/gc,tmp2=q[x]/gc;
	p[x]=p[x]*tmp1+y*tmp2;
	q[x]=gc;
	int tt=gcd(p[x],q[x]);
	p[x]/=tt;
	q[x]/=tt;
//	cout<<p[x]<<" "<<q[x]<<"\n";
}
void topo()
{
	queue<int> qq;
	for(int i=1;i<=n;i++)
	{
		if(ru[i]==0)
		{
			vis[i]=1;
			qq.push(i);
		}
	}
	while(!qq.empty())
	{
		int u=qq.front();
		qq.pop();
//		cout<<u<<endl;
//		cout<<u<<" aa"<<endl;
		for(int i=0;i<g[u].size();i++) 
		{
			int v=g[u][i];
//			cout<<v<<" bb"<<endl;
//			cout<<"   "<<v<<endl;
			add(v,p[u],q[u]*((ll)g[u].size()));
//			cout<<"   bb"<<endl;
//			cout<<"cc"<<endl;
			if(vis[v]) continue;
			ru[v]--;
			if(ru[v]==0)
			{
				vis[v]=1;
				qq.push(v);
			}
		}
		if(g[u].size()>0) p[u]=0;
	}
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen("P7113_7.in","r",stdin);
//	freopen("my.out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		int x;
		cin>>x;
		chu[i]=x;
		for(int j=1;j<=x;j++)
		{
			int v;
			cin>>v;
			ru[v]++;
			g[i].push_back(v);
		}
	}
	for(int i=1;i<=n;i++)
	{
		q[i]=1;
		if(ru[i]==0) p[i]=1;
	}
	topo();
	for(int i=1;i<=n;i++)
	{
		if(p[i]!=0) cout<<p[i]<<" "<<q[i]<<"\n";
	}
	return 0;
}
